19	/// An AXI4 interface.
20	interface AXI_BUS #(
21	  parameter int unsigned AXI_ADDR_WIDTH = 0,
22	  parameter int unsigned AXI_DATA_WIDTH = 0,
23	  parameter int unsigned AXI_ID_WIDTH   = 0,
24	  parameter int unsigned AXI_USER_WIDTH = 0
25	);
26	
27	  localparam int unsigned AXI_STRB_WIDTH = AXI_DATA_WIDTH / 8;
28	
29	  typedef logic [AXI_ID_WIDTH-1:0]   id_t;
30	  typedef logic [AXI_ADDR_WIDTH-1:0] addr_t;
31	  typedef logic [AXI_DATA_WIDTH-1:0] data_t;
32	  typedef logic [AXI_STRB_WIDTH-1:0] strb_t;
33	  typedef logic [AXI_USER_WIDTH-1:0] user_t;
34	
35	  id_t              aw_id;
36	  addr_t            aw_addr;
37	  axi_pkg::len_t    aw_len;
38	  axi_pkg::size_t   aw_size;
39	  axi_pkg::burst_t  aw_burst;
40	  logic             aw_lock;
41	  axi_pkg::cache_t  aw_cache;
42	  axi_pkg::prot_t   aw_prot;
43	  axi_pkg::qos_t    aw_qos;
44	  axi_pkg::region_t aw_region;
45	  axi_pkg::atop_t   aw_atop;
46	  user_t            aw_user;
47	  logic             aw_valid;
48	  logic             aw_ready;
49	
50	  data_t            w_data;
51	  strb_t            w_strb;
52	  logic             w_last;
53	  user_t            w_user;
54	  logic             w_valid;
55	  logic             w_ready;
56	
57	  id_t              b_id;
58	  axi_pkg::resp_t   b_resp;
59	  user_t            b_user;
60	  logic             b_valid;
61	  logic             b_ready;
62	
63	  id_t              ar_id;
64	  addr_t            ar_addr;
65	  axi_pkg::len_t    ar_len;
66	  axi_pkg::size_t   ar_size;
67	  axi_pkg::burst_t  ar_burst;
68	  logic             ar_lock;
69	  axi_pkg::cache_t  ar_cache;
70	  axi_pkg::prot_t   ar_prot;
71	  axi_pkg::qos_t    ar_qos;
72	  axi_pkg::region_t ar_region;
73	  user_t            ar_user;
74	  logic             ar_valid;
75	  logic             ar_ready;
76	
77	  id_t              r_id;
78	  data_t            r_data;
79	  axi_pkg::resp_t   r_resp;
80	  logic             r_last;
81	  user_t            r_user;
82	  logic             r_valid;
83	  logic             r_ready;
84	
85	  modport Master (
86	    output aw_id, aw_addr, aw_len, aw_size, aw_burst, aw_lock, aw_cache, aw_prot, aw_qos, aw_region, aw_atop, aw_user, aw_valid, input aw_ready,
87	    output w_data, w_strb, w_last, w_user, w_valid, input w_ready,
88	    input b_id, b_resp, b_user, b_valid, output b_ready,
89	    output ar_id, ar_addr, ar_len, ar_size, ar_burst, ar_lock, ar_cache, ar_prot, ar_qos, ar_region, ar_user, ar_valid, input ar_ready,
90	    input r_id, r_data, r_resp, r_last, r_user, r_valid, output r_ready
91	  );
92	
93	  modport Slave (
94	    input aw_id, aw_addr, aw_len, aw_size, aw_burst, aw_lock, aw_cache, aw_prot, aw_qos, aw_region, aw_atop, aw_user, aw_valid, output aw_ready,
95	    input w_data, w_strb, w_last, w_user, w_valid, output w_ready,
96	    output b_id, b_resp, b_user, b_valid, input b_ready,
97	    input ar_id, ar_addr, ar_len, ar_size, ar_burst, ar_lock, ar_cache, ar_prot, ar_qos, ar_region, ar_user, ar_valid, output ar_ready,
98	    output r_id, r_data, r_resp, r_last, r_user, r_valid, input r_ready
99	  );
