112	/// A clocked AXI4 interface for use in design verification.
113	interface AXI_BUS_DV #(
114	  parameter int unsigned AXI_ADDR_WIDTH = 0,
115	  parameter int unsigned AXI_DATA_WIDTH = 0,
116	  parameter int unsigned AXI_ID_WIDTH   = 0,
117	  parameter int unsigned AXI_USER_WIDTH = 0
118	)(
119	  input logic clk_i
120	);
121	
122	  localparam int unsigned AXI_STRB_WIDTH = AXI_DATA_WIDTH / 8;
123	
124	  typedef logic [AXI_ID_WIDTH-1:0]   id_t;
125	  typedef logic [AXI_ADDR_WIDTH-1:0] addr_t;
126	  typedef logic [AXI_DATA_WIDTH-1:0] data_t;
127	  typedef logic [AXI_STRB_WIDTH-1:0] strb_t;
128	  typedef logic [AXI_USER_WIDTH-1:0] user_t;
129	
130	  id_t              aw_id;
131	  addr_t            aw_addr;
132	  axi_pkg::len_t    aw_len;
133	  axi_pkg::size_t   aw_size;
134	  axi_pkg::burst_t  aw_burst;
135	  logic             aw_lock;
136	  axi_pkg::cache_t  aw_cache;
137	  axi_pkg::prot_t   aw_prot;
138	  axi_pkg::qos_t    aw_qos;
139	  axi_pkg::region_t aw_region;
140	  axi_pkg::atop_t   aw_atop;
141	  user_t            aw_user;
142	  logic             aw_valid;
143	  logic             aw_ready;
144	
145	  data_t            w_data;
146	  strb_t            w_strb;
147	  logic             w_last;
148	  user_t            w_user;
149	  logic             w_valid;
150	  logic             w_ready;
151	
152	  id_t              b_id;
153	  axi_pkg::resp_t   b_resp;
154	  user_t            b_user;
155	  logic             b_valid;
156	  logic             b_ready;
157	
158	  id_t              ar_id;
159	  addr_t            ar_addr;
160	  axi_pkg::len_t    ar_len;
161	  axi_pkg::size_t   ar_size;
162	  axi_pkg::burst_t  ar_burst;
163	  logic             ar_lock;
164	  axi_pkg::cache_t  ar_cache;
165	  axi_pkg::prot_t   ar_prot;
166	  axi_pkg::qos_t    ar_qos;
167	  axi_pkg::region_t ar_region;
168	  user_t            ar_user;
169	  logic             ar_valid;
170	  logic             ar_ready;
171	
172	  id_t              r_id;
173	  data_t            r_data;
174	  axi_pkg::resp_t   r_resp;
175	  logic             r_last;
176	  user_t            r_user;
177	  logic             r_valid;
178	  logic             r_ready;
179	
180	  modport Master (
181	    output aw_id, aw_addr, aw_len, aw_size, aw_burst, aw_lock, aw_cache, aw_prot, aw_qos, aw_region, aw_atop, aw_user, aw_valid, input aw_ready,
182	    output w_data, w_strb, w_last, w_user, w_valid, input w_ready,
183	    input b_id, b_resp, b_user, b_valid, output b_ready,
184	    output ar_id, ar_addr, ar_len, ar_size, ar_burst, ar_lock, ar_cache, ar_prot, ar_qos, ar_region, ar_user, ar_valid, input ar_ready,
185	    input r_id, r_data, r_resp, r_last, r_user, r_valid, output r_ready
186	  );
187	
188	  modport Slave (
189	    input aw_id, aw_addr, aw_len, aw_size, aw_burst, aw_lock, aw_cache, aw_prot, aw_qos, aw_region, aw_atop, aw_user, aw_valid, output aw_ready,
190	    input w_data, w_strb, w_last, w_user, w_valid, output w_ready,
191	    output b_id, b_resp, b_user, b_valid, input b_ready,
192	    input ar_id, ar_addr, ar_len, ar_size, ar_burst, ar_lock, ar_cache, ar_prot, ar_qos, ar_region, ar_user, ar_valid, output ar_ready,
193	    output r_id, r_data, r_resp, r_last, r_user, r_valid, input r_ready
194	  );
195	
196	  modport Monitor (
197	    input aw_id, aw_addr, aw_len, aw_size, aw_burst, aw_lock, aw_cache, aw_prot, aw_qos, aw_region, aw_atop, aw_user, aw_valid, aw_ready,
198	          w_data, w_strb, w_last, w_user, w_valid, w_ready,
199	          b_id, b_resp, b_user, b_valid, b_ready,
200	          ar_id, ar_addr, ar_len, ar_size, ar_burst, ar_lock, ar_cache, ar_prot, ar_qos, ar_region, ar_user, ar_valid, ar_ready,
201	          r_id, r_data, r_resp, r_last, r_user, r_valid, r_ready
202	  );
203	
204	  // pragma translate_off
205	  `ifndef VERILATOR
206	  // Single-Channel Assertions: Signals including valid must not change between valid and handshake.
207	  // AW
208	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_id)));
209	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_addr)));
210	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_len)));
211	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_size)));
212	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_burst)));
213	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_lock)));
214	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_cache)));
215	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_prot)));
216	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_qos)));
217	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_region)));
218	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_atop)));
219	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> $stable(aw_user)));
220	  assert property (@(posedge clk_i) (aw_valid && !aw_ready |=> aw_valid));
221	  // W
222	  assert property (@(posedge clk_i) ( w_valid && ! w_ready |=> $stable(w_data)));
223	  assert property (@(posedge clk_i) ( w_valid && ! w_ready |=> $stable(w_strb)));
224	  assert property (@(posedge clk_i) ( w_valid && ! w_ready |=> $stable(w_last)));
225	  assert property (@(posedge clk_i) ( w_valid && ! w_ready |=> $stable(w_user)));
226	  assert property (@(posedge clk_i) ( w_valid && ! w_ready |=> w_valid));
227	  // B
228	  assert property (@(posedge clk_i) ( b_valid && ! b_ready |=> $stable(b_id)));
229	  assert property (@(posedge clk_i) ( b_valid && ! b_ready |=> $stable(b_resp)));
230	  assert property (@(posedge clk_i) ( b_valid && ! b_ready |=> $stable(b_user)));
231	  assert property (@(posedge clk_i) ( b_valid && ! b_ready |=> b_valid));
232	  // AR
233	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_id)));
234	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_addr)));
235	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_len)));
236	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_size)));
237	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_burst)));
238	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_lock)));
239	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_cache)));
240	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_prot)));
241	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_qos)));
242	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_region)));
243	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> $stable(ar_user)));
244	  assert property (@(posedge clk_i) (ar_valid && !ar_ready |=> ar_valid));
245	  // R
246	  assert property (@(posedge clk_i) ( r_valid && ! r_ready |=> $stable(r_id)));
247	  assert property (@(posedge clk_i) ( r_valid && ! r_ready |=> $stable(r_data)));
248	  assert property (@(posedge clk_i) ( r_valid && ! r_ready |=> $stable(r_resp)));
249	  assert property (@(posedge clk_i) ( r_valid && ! r_ready |=> $stable(r_last)));
250	  assert property (@(posedge clk_i) ( r_valid && ! r_ready |=> $stable(r_user)));
251	  assert property (@(posedge clk_i) ( r_valid && ! r_ready |=> r_valid));
252	  // Address-Channel Assertions: The address of the  last beat of a burst must be on the same 4 KiB
253	  // page as the address of the first beat of a burst. Bus is always word-aligned, word < page.
254	  assert property (@(posedge clk_i) aw_valid |-> (aw_burst != axi_pkg::BURST_INCR) || (
255	    axi_pkg::beat_addr(aw_addr, aw_size, aw_len, aw_burst, 0) >> 12 ==    // lowest beat address
256	    axi_pkg::beat_addr(aw_addr, aw_size, aw_len, aw_burst, aw_len) >> 12  // highest beat address
257	  )) else $error("AW burst crossing 4 KiB page boundary detected, which is illegal!");
258	  assert property (@(posedge clk_i) ar_valid |-> (aw_burst != axi_pkg::BURST_INCR) || (
259	    axi_pkg::beat_addr(ar_addr, ar_size, ar_len, ar_burst, 0) >> 12 ==    // lowest beat address
260	    axi_pkg::beat_addr(ar_addr, ar_size, ar_len, ar_burst, ar_len) >> 12  // highest beat address
261	  )) else $error("AR burst crossing 4 KiB page boundary detected, which is illegal!");
262	  `endif
263	  // pragma translate_on
264	
265	endinterface
