358	/// An asynchronous AXI4 interface for Gray CDCs.
359	interface AXI_BUS_ASYNC_GRAY #(
360	  parameter int unsigned AXI_ADDR_WIDTH = 0,
361	  parameter int unsigned AXI_DATA_WIDTH = 0,
362	  parameter int unsigned AXI_ID_WIDTH = 0,
363	  parameter int unsigned AXI_USER_WIDTH = 0,
364	  parameter int unsigned LOG_DEPTH = 0
365	);
366	
367	  localparam int unsigned AXI_STRB_WIDTH = AXI_DATA_WIDTH / 8;
368	
369	  typedef logic [AXI_ID_WIDTH-1:0]   id_t;
370	  typedef logic [AXI_ADDR_WIDTH-1:0] addr_t;
371	  typedef logic [AXI_DATA_WIDTH-1:0] data_t;
372	  typedef logic [AXI_STRB_WIDTH-1:0] strb_t;
373	  typedef logic [AXI_USER_WIDTH-1:0] user_t;
374	
375	  `AXI_TYPEDEF_AW_CHAN_T(aw_chan_t, addr_t, id_t, user_t)
376	  `AXI_TYPEDEF_W_CHAN_T(w_chan_t, data_t, strb_t, user_t)
377	  `AXI_TYPEDEF_B_CHAN_T(b_chan_t, id_t, user_t)
378	  `AXI_TYPEDEF_AR_CHAN_T(ar_chan_t, addr_t, id_t, user_t)
379	  `AXI_TYPEDEF_R_CHAN_T(r_chan_t, data_t, id_t, user_t)
380	
381	  aw_chan_t  [2**LOG_DEPTH-1:0] aw_data;
382	  w_chan_t   [2**LOG_DEPTH-1:0] w_data;
383	  b_chan_t   [2**LOG_DEPTH-1:0] b_data;
384	  ar_chan_t  [2**LOG_DEPTH-1:0] ar_data;
385	  r_chan_t   [2**LOG_DEPTH-1:0] r_data;
386	  logic           [LOG_DEPTH:0] aw_wptr,  aw_rptr,
387	                                w_wptr,   w_rptr,
388	                                b_wptr,   b_rptr,
389	                                ar_wptr,  ar_rptr,
390	                                r_wptr,   r_rptr;
391	
392	  modport Master (
393	    output aw_data, aw_wptr, input aw_rptr,
394	    output w_data, w_wptr, input w_rptr,
395	    input b_data, b_wptr, output b_rptr,
396	    output ar_data, ar_wptr, input ar_rptr,
397	    input r_data, r_wptr, output r_rptr);
398	
399	  modport Slave (
400	    input aw_data, aw_wptr, output aw_rptr,
401	    input w_data, w_wptr, output w_rptr,
402	    output b_data, b_wptr, input b_rptr,
403	    input ar_data, ar_wptr, output ar_rptr,
404	    output r_data, r_wptr, input r_rptr);
405	
406	endinterface
