409	/// An AXI4-Lite interface.
410	interface AXI_LITE #(
411	  parameter int unsigned AXI_ADDR_WIDTH = 0,
412	  parameter int unsigned AXI_DATA_WIDTH = 0
413	);
414	
415	  localparam int unsigned AXI_STRB_WIDTH = AXI_DATA_WIDTH / 8;
416	
417	  typedef logic [AXI_ADDR_WIDTH-1:0] addr_t;
418	  typedef logic [AXI_DATA_WIDTH-1:0] data_t;
419	  typedef logic [AXI_STRB_WIDTH-1:0] strb_t;
420	
421	  // AW channel
422	  addr_t          aw_addr;
423	  axi_pkg::prot_t aw_prot;
424	  logic           aw_valid;
425	  logic           aw_ready;
426	
427	  data_t          w_data;
428	  strb_t          w_strb;
429	  logic           w_valid;
430	  logic           w_ready;
431	
432	  axi_pkg::resp_t b_resp;
433	  logic           b_valid;
434	  logic           b_ready;
